VALUES
  ('social-worker-moex-02561', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '方案評估者在一個以促進青少年人際關係為目的（objective）的方案中，僅以參與方案的青少年為評估對 象，請問最能精確評估方案能否促進青少年人際關係的評估方法是下列何者？', '["古典實驗設計", "單組後測設計", "單組前後測設計", "形成性評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02562', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志工為服務對象所作的貢獻，應該受到志願服務運用單位正式與非正式的肯定及激勵。下列那一項是正 式肯定及激勵的方式？', '["推薦志工參加其他訓練", "邀請志工參與會影響他們的決策", "舉辦感恩會並頒發感謝狀", "打電話感謝志工的家人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02563', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '性別主流化（gender mainstreaming）是當前世界各國推動性別平等的核心策略，下列有關性別主流化的敘 述，何者錯誤？', '["性別主流化策略應成為公部門執行業務的常規", "為符合性別平等的一致性原則，原本針對女性的扶助和充權政策應予取消", "性別主流化認為不能將社會政策需求，化約至單一性別思維", "性別主流化需有科學方法和分析工具，以確保所訂政策沒有成見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02564', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案設計與執行過程，方案設計者特別關注社會工作個別化服務的原則，此原則最接近下列那一項品 質面向？', '["可近性（accessibility）", "保證（assurance）", "同理（empathy）", "回應（responsiveness）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02565', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'essay', '為擘劃我國未來性別平等的方向，行政院於民國100年12月19日函頒「性別平等
政策綱領」，作為政策指導方針，綱領內容揭櫫三大基本理念。請說明這三大基本
理念為何？並申論在人口、婚姻與家庭面，我國應強調那些政策內涵？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02566', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'essay', '隨著幾次社會工作人員遭逢暴力相向的事件，社會工作人員之人身安全的議題受到
關注，衛生福利部擬以「社會工作人員執業安全條例」專法以為因應。請以美國密
西根州「麗莎法案」（Lisa’s Law）為例，申論我國社會工作人員人身安全專法應
涵蓋那些重要措施？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02567', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '不同意識型態者對於戰後福利國家有不同的看法。某些論者將福利國家視作一種鞏固資本家利益的政治 手段，請問：這是下列那種論點或學派對福利國家的評價？', '["社會民主觀點", "新自由主義", "新馬克思主義", "第三條路"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02568', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '1970 年代之後西方福利國家在發展上與政治上均陷入危機，許多論者對其進行批判，其中女性主義從 「性別」的角度提出批判。下列那一個論述，不屬於女性主義對福利國家的批判？', '["多數福利供給以「工作的取得」作為前提，而女性在勞動市場的劣勢處境，導致女性無法在福利體系 中獲得和男性同等的公民權利保障", "福利國家摧毀家庭倫理，福利供給的存在不僅抑制低薪工人的工作動機，也削弱了女性對男性的經濟 依賴，導致傳統上由夫妻組成的核心家庭解組", "女性是潛在的「勞動預備軍」，可以被國家拿來當作抑制工人工資的武器，穩定既有的勞動力", "福利國家將福利責任丟給女性，以女性的無酬勞動來分擔國家照顧責任的成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02569', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會福利政策形成與發展的過程中，整個社會以及政策規劃者對於個人主義與集體主義的意識型態立場， 具關鍵性的影響。下列關於個人主義與集體主義間差異的描述，何者錯誤？', '["個人主義者對國家的干預抱持戒慎恐懼的態度，集體主義則不然", "由於經歷過兩次大戰期間的經濟大蕭條，因此相較於歐洲社會，美國社會在意識型態上較傾向集體主義", "在給付形式的選擇上，個人主義者由於較看重領受者作為消費者的「選擇自由」，因此較偏好現金型 的給付形式", "相較於集體主義者，個人主義者更相信「個人需對自己所處的境遇負起責任」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02570', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '除了透過直接提供現金或服務外，有時政府在經費限制的情況下也可以透過法制的力量，將回應某些弱 勢人口群需要的責任強加在私人或民間單位身上，以減少弱勢者對政府公共方案的需求，這樣的作法又 被稱作「規範性福利」（regulatory welfare）。請問：下列那一個福利項目不具備「規範性福利」的意涵？', '["父母未就業家庭育兒津貼", "育嬰留職停薪休假", "女性勞工分娩後之8星期帶薪產假", "身障者定額進用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02571', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會福利給付計畫或方案的形成與運作過程大致涵蓋幾個階段：定義政策問題、形成政策計畫、政策合法 化、執行社會政策、評估社會政策。請問：關於「政策合法化」這個階段，下列那一個選項的描述正確？', '["社會需求未得到滿足，公眾強烈要求政府形成政策來回應未被滿足的需求", "來自官方與民間的各方團體開始進行權力角力，以競逐對福利計畫或方案運作方向的影響力", "計畫與方案已執行到一個段落，政府與專家、以及民間團體開始對其影響與成本效益進行各種正式和 非正式的評估", "政府開始透過各種管道去蒐集訊息與資訊，以凝聚明確的政策目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02572', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在社會福利計畫或方案的形成與運作過程中，為何某些人在整個過程擁有較大影響力？「菁英論」與 「多元論」的立場剛好相反。下列關於兩者的描述，何者錯誤？', '["臺灣在解嚴前有許多由上而下推動的社會政策，如：勞工保險條例。對於這類政策菁英論有不錯的解 釋效果", "近年來，關於基本工資訂定的審議，勞方與資方會透過壓力團體的運作去影響審議結果，菁英論也有 不錯的解釋效果", "對多元論者來說，權力並非集中在少數菁英手中，而是廣泛地分散在不同團體之中", "多元論認為：政府面對不同立場與不同意見的表達時，其責任是去尋求團體之間的折衝與利益均衡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02573', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '1990 年代之後，勞動政策成為社會政策中相當重要的環節，原因之一在於經濟全球化嚴重衝擊工業先進 國家的勞動市場運作與結構。下列關於90年代之後的工業先進國家勞動市場變遷描述，何者錯誤？', '["工業先進國家的去工業化，導致製造部門的工作不斷流失，中高齡藍領男性的就業機會受到最大的影響", "非典型就業型態的擴張，使得雇主在運用人力上更為彈性", "服務業與知識產業興起，也導致勞動市場所得日益兩極化", "勞力的跨國移動增加，主要集中在白領勞動者。近年來越來越多企業將員工外派至大陸擔任中階主管 即屬一例"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02574', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在福利私有化的趨勢下，福利輸送的來源不再獨尊政府；除了「政府部門」外，「非正式部門」、「志 願部門」與「商業部門」也是重要來源。在福利輸送過程中，這四個部門有各自的特點，彼此之間也存 在互動。下列關於四個部門的描述，何者錯誤？', '["志願部門雖然以非營利為導向，但在運作過程中仍容許利潤的賸餘，只不過利潤不能用於私人性的目的", "非正式部門係指以家庭為中心而延伸出的親屬網絡。隨著家庭不穩定的增加以及家庭型態的轉變，此 部門的福利輸送能力有日益衰退的跡象", "商業部門是以利潤的追求作為其行動邏輯，因此政府在契約委託時，應避免其營利屬性破壞社會福利 對公正與安全價值的追求", "政府將福利服務透過公設民營或契約委外，交由志願部門或商業部門輸送時，應儘可能鬆綁規範， 不為福利服務設定任何標準，讓兩部門的參與者有最大的空間去發揮創意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02575', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '福利給付或多或少會抑制領受者的工作動機，關於這部分的討論，「失業陷阱」是很重要的概念。下列 關於「失業陷阱」的描述，何者錯誤？', '["此概念的定義為：領受者努力賺錢，反倒因為面臨失去福利資格或較高的所得稅率而得不到更好的結 果，如此將抑制領受者透過工作脫離貧窮的動機", "一般來說，凡是現金形式的給付都會有失業陷阱；保險型的給付相較於救助型的給付更容易有失業陷阱", "為避免失業陷阱，給付制度在設計上除要留意領受者的實際所得外，也可以透過提供實質誘因，避免 領受者因工作所得增加而整體收入下降", "我國就業保險法中的「提早就業奬助津貼」即有避免失業陷阱的效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02576', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '1980 年代後「新管理主義」的思潮對福利服務輸送產生影響，請問：下列關於福利服務輸送的陳述， 那一個選項跟新管理主義的影響無關？', '["政府部門被期待仿效企業的運作方式，在組織運作上更為扁平化與彈性，這亦間接促成福利私有化的 趨勢", "家庭外部照顧服務體系的興起，某些國家透過市場供給的方式來回應，某些則由政府透過現金補貼或 公共服務的建立來回應", "政府部門與社會福利機構為了對福利服務的產出作更嚴密的控制，相當看重績效指標的建立與績效的 衡量方法", "過去弱勢者被稱呼為「案主」，近年來，已逐漸被「消費者」或「顧客」這樣的概念所取代"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02577', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '相較於社會保險與社會救助，社會津貼具有某些特質。下列關於社會津貼的描述，何者錯誤？', '["基於公民權或居留權的普及性給付", "考量領受者的所得水準，採取所得相關給付，所得越高，領取水準越高", "財源主要來自一般稅收", "雖然財務規模大，但因無須進行個案審查，所以行政成本低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02578', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會福利政策的財源有很大部分來自政府的稅收。因此財稅制度會深刻地影響社會福利政策的重分配效 果。一般來說，若依租稅對資源的重分配程度，稅制可分成兩大類：累進稅（progressive tax）與累退稅 （regressive tax）。請問：下列那一種類型租稅項目為「累退稅」？', '["所得稅", "遺產稅", "社會安全稅", "加值型營業稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02579', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問那位學者對捐血行為作研究，發現人們願意對陌生人捐血，以彰顯利他主義的精神？', '["Richard Titmuss", "Alva Myrdal", "Robert Pinker", "Peter Baldwin"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02580', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '行政院在2012年10月成立「年金制度改革小組」，研議整體年金改革相關事宜，該小組秉持四大原則 進行改革規劃，下列所述原則何者錯誤？', '["社會公平", "財務健全", "世代包容", "政府責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02581', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國於2001年制定「消除對婦女一切形式歧視公約施行法」，下列條文內容描述，何者錯誤？', '["公約所揭示保障性別人權及促進性別平等之規定，具有國內法律之效力", "政府應依公約規定，建立消除對婦女一切形式歧視報告制度，每2年提出國家報告", "各級政府機關執行公約保障各項性別人權規定所需之經費，應依財政狀況優先編列", "各級政府機關應依公約規定之內容，檢討所主管之法規及行政措施，有不符公約規定者，應於本法施 行後3年內，完成法規之制（訂）定、修正或廢止及行政措施之改進"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02582', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '行政院於2004年制定「家庭政策」，下列何者不是我國家庭政策制定的原則？', '["充權家內與家庭間的弱勢者", "尊重傳統家庭價值", "公平照顧家庭成員的福祉，並兼顧差別正義的原則", "促進家庭的整合"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02583', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國為配合實施聯合國在2006年身心障礙者權利公約，特別制定「身心障礙者權利公約施行法」，其條 文共12條，下列所述何者錯誤？', '["公約所揭示保障身心障礙者人權之規定，具有國內法律之效力", "行政院為推動本公約相關工作，應邀集學者專家、身心障礙團體（機構）及各政府機關代表成立身心 障礙者權益推動小組。而前項學者專家、身心障礙團體（機構）之人數不得少於總數二分之一，任一 性別不得少於三分之一", "政府應依公約規定建立身心障礙者權利報告制度，於本法施行後2年提出初次國家報告，之後每5年 提出國家報告", "各級政府機關應依公約規定之內容，就其所主管之法規及行政措施於本法實施後 2 年內提出優先檢視 清單"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02584', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '針對人口老化問題並為提升老人之健康促進與社會參與。行政院曾於2009年9月核定「友善關懷老人服 務方案」，並自2014年1月起推動該方案第二期計畫。此計畫訂有五大目標，下列何者不是目標之一？', '["提倡預防保健、促進健康老化", "建置友善環境、促進在地老化", "引進民間投入、促進活力老化", "鼓勵終身學習、促進樂學老化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02585', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為響應聯合國「國際女童日」精神，重視投資及培力女孩，讓女孩獲得應有的人權與照顧，我國將每年 幾月幾日訂為「臺灣女孩日」？', '["4月2日", "4月4日", "10月11日", "12月5日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
